    13→export default function App() {
    14→  const { token, me, setAuth, logout, setWsConnected, addToast,
    15→    appendMessage, updateMessage, deleteMessage, updateConvLastMessage,
    16→    incrementUnread, activeConvId, setTyping, setIncomingCall,
    17→    activeCall, setActiveCall, incomingCall, updateMe, conversations,
    18→    appendChannelMessage, activeChannelId } = useStore()
