    20→  const wsRef = useRef(null)
    21→  const pingRef = useRef(null)
    22→
    23→  useEffect(() => {
    24→    applyTheme('violet')
    25→    // Load saved session
    26→    ;(async () => {
    27→      try {
    28→        const cfg = await window.electron?.config.load() || {}
    29→        if (cfg.token) {
    30→          const res = await get('/api/auth/me', { token: cfg.token })
    31→          if (res.ok) {
    32→            setAuth(cfg.token, res.data)
