    45→      clearInterval(pingRef.current)
    46→      return
    47→    }
    48→
    49→    const ws = new WSClient({
    50→      onConnect: () => {
    51→        setWsConnected(true)
    52→      },
    53→      onDisconnect: () => {
    54→        setWsConnected(false)
    55→      },
    56→      onMessage: (msg) => handleWsMessage(msg),
    57→    })
    58→    ws.connect(token)
    59→    wsInstance = ws
    60→    wsRef.current = ws
    61→
    62→    pingRef.current = setInterval(() => ws.send({ type: 'ping' }), 30000)
    63→
    64→    return () => {
    65→      ws.disconnect()
