    70→  function handleWsMessage(msg) {
    71→    const store = useStore.getState()
    72→
    73→    switch (msg.type) {
    74→      case 'new_message': {
    75→        const { conversationId, message } = msg
    76→        store.appendMessage(conversationId, message)
    77→        store.updateConvLastMessage(conversationId, message)
    78→        if (conversationId !== store.activeConvId) {
    79→          store.incrementUnread(conversationId)
    80→          if (message.sender?.id !== store.me?.id) {
    81→            store.addToast({
    82→              title: message.sender?.displayName || message.sender?.username,
    83→              body: message.content,
    84→              type: 'message',
    85→            })
    86→            window.electron?.notify({
    87→              title: message.sender?.displayName || message.sender?.username,
    88→              body: message.content?.slice(0, 80),
