    90→          }
    91→        }
    92→        break
    93→      }
    94→      case 'message_edited': {
    95→        const { conversationId, messageId, content } = msg
    96→        store.updateMessage(conversationId, messageId, { content, edited: true })
    97→        break
    98→      }
    99→      case 'message_deleted': {
   100→        const { conversationId, messageId } = msg
   101→        store.deleteMessage(conversationId, messageId)
   102→        break
   103→      }
   104→      case 'message_reaction': {
   105→        const { conversationId, messageId, reactions } = msg
   106→        store.updateMessage(conversationId, messageId, { reactions })
   107→        break
   108→      }
   109→      case 'typing': {
   110→        const { conversationId, username } = msg
   111→        const cur = store.typing[conversationId] || []
   112→        if (!cur.includes(username)) {
   113→          store.setTyping(conversationId, [...cur, username])
   114→          setTimeout(() => {
   115→            const now = useStore.getState().typing[conversationId] || []
   116→            store.setTyping(conversationId, now.filter(u => u !== username))
   117→          }, 3000)
   118→        }
   119→        break
   120→      }
   121→      case 'incoming_call': {
   122→        store.setIncomingCall(msg)
   123→        break
   124→      }
   125→      case 'call_accepted': {
   126→        store.setActiveCall(store.activeCall ? { ...store.activeCall, state: 'connected', startTime: Date.now() } : null)
   127→        break
   128→      }
   129→      case 'call_rejected': {
   130→        store.activeCall?.audio?.stop()
   131→        store.setActiveCall(null)
   132→        store.addToast({ title: 'Звонок', body: 'Собеседник отклонил звонок', type: 'info' })
   133→        break
   134→      }
   135→      case 'call_ended': {
   136→        store.activeCall?.audio?.stop()
   137→        store.setActiveCall(null)
   138→        break
   139→      }
   140→      case 'call_unavailable': {
   141→        store.activeCall?.audio?.stop()
   142→        store.setActiveCall(null)
   143→        store.addToast({ title: 'Звонок', body: 'Пользователь недоступен', type: 'info' })
   144→        break
   145→      }
   146→      case 'call_audio': {
   147→        store.activeCall?.audio?.receive(msg.audio)
   148→        break
   149→      }
   150→      case 'coins_added': {
   151→        store.updateMe({ coins: msg.coins })
   152→        store.addToast({ title: '💰 Монеты', body: `Начислено ${msg.amount} монет`, type: 'success' })
   153→        break
   154→      }
   155→      case 'premium_activated': {
   156→        store.updateMe({ isPremium: true, premiumUntil: msg.until })
   157→        store.addToast({ title: '⭐ Premium', body: 'Premium активирован!', type: 'success' })
   158→        break
   159→      }
   160→      case 'force_logout': {
   161→        store.addToast({ title: 'Сессия завершена', body: msg.reason || '', type: 'error' })
   162→        setTimeout(() => store.logout(), 2000)
   163→        break
   164→      }
   165→      case 'account_frozen': {
   166→        store.addToast({ title: '❄️ Аккаунт заморожен', body: msg.reason || '', type: 'error' })
   167→        setTimeout(() => store.logout(), 3000)
   168→        break
   169→      }
   170→      case 'account_muted': {
   171→        store.addToast({ title: '🔇 Вы замьючены', body: `До ${msg.until || 'снятия'}`, type: 'warning' })
   172→        break
   173→      }
   174→      case 'new_channel_message': {
   175→        const { channelId, message } = msg
   176→        store.appendChannelMessage(channelId, message)
   177→        break
   178→      }
   179→      case 'channel_message_edited': {
   180→        // handled by server panel
   181→        break
   182→      }
   183→    }
   184→  }
   185→
   186→  function getWs() { return wsRef.current }
   187→
   188→  return (
   189→    <>
   190→      {!token
   191→        ? <AuthPage />
   192→        : <MainPage getWs={getWs} />
   193→      }
   194→      <ToastContainer />
   195→      {incomingCall && <IncomingCallModal call={incomingCall} getWs={getWs} />}
   196→      {activeCall && <ActiveCallWindow getWs={getWs} />}
   197→    </>
   198→  )
   199→}
