     1→const BASE_URL = 'https://omnii.duckdns.org:3000'
     2→
     3→let _token = null
     4→
     5→export function setToken(t) { _token = t }
     6→export function getToken() { return _token }
     7→
     8→export async function api(method, path, opts = {}) {
     9→  const { token, json, form, params } = opts
    10→  const headers = { 'X-Client-Version': '3.0.0' }
    11→  const tok = token ?? _token
    12→  if (tok) headers['Authorization'] = `Bearer ${tok}`
    13→
    14→  let url = BASE_URL + path
    15→  if (params) {
    16→    const q = new URLSearchParams(params)
    17→    url += '?' + q.toString()
    18→  }
    19→
    20→  const fetchOpts = { method, headers }
    21→
    22→  if (json !== undefined) {
    23→    headers['Content-Type'] = 'application/json'
    24→    fetchOpts.body = JSON.stringify(json)
    25→  }
    26→  if (form) {
    27→    fetchOpts.body = form
    28→  }
    29→
    30→  const res = await fetch(url, fetchOpts)
    31→  const data = await res.json().catch(() => ({}))
    32→  return { ok: res.ok, status: res.status, data }
    33→}
    34→
    35→export const get  = (path, opts) => api('GET',    path, opts)
    36→export const post = (path, opts) => api('POST',   path, opts)
    37→export const put  = (path, opts) => api('PUT',    path, opts)
    38→export const patch= (path, opts) => api('PATCH',  path, opts)
    39→export const del  = (path, opts) => api('DELETE', path, opts)
