   440→function groupByDate(msgs) {
   441→  const groups = {}
   442→  for (const msg of msgs) {
   443→    const d = fmtDay(msg.createdAt)
   444→    if (!groups[d]) groups[d] = []
   445→    groups[d].push(msg)
   446→  }
   447→  return Object.entries(groups).map(([date, messages]) => ({ date, messages }))
   448→}
   449→
   450→function fmtTime(ts) {
   451→  try {
   452→    return new Date(ts).toLocaleTimeString('ru', { hour: '2-digit', minute: '2-digit' })
   453→  } catch { return '' }
   454→}
   455→
   456→function fmtDay(ts) {
   457→  try {
   458→    const d = new Date(ts)
   459→    const now = new Date()
   460→    if (d.toDateString() === now.toDateString()) return 'Сегодня'
   461→    const y = new Date(now); y.setDate(now.getDate() - 1)
   462→    if (d.toDateString() === y.toDateString()) return 'Вчера'
   463→    return d.toLocaleDateString('ru', { day: '2-digit', month: 'long', year: 'numeric' })
   464→  } catch { return '' }
   465→}
